import React, { useEffect, useState, useCallback } from "react";
import axios from "axios";
import { useParams, useNavigate } from "react-router-dom";

export default function ProductosPorCategoria() {
  const { categoria_id } = useParams();
  const navigate = useNavigate();

  const [productos, setProductos] = useState([]);
  const [loading, setLoading] = useState(true);

  const [showModal, setShowModal] = useState(false);

const [nuevoProducto, setNuevoProducto] = useState({
  nombre: "",
  descripcion: "",
  precio: "",
  stock: "",
  imagen: null,
});

  // 📄 PAGINACIÓN
  const [paginaActual, setPaginaActual] = useState(1);
  const productosPorPagina = 8;

  const obtenerProductos = useCallback(async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/productos/categoria/${categoria_id}`
      );

      setProductos(
        res.data.map((p) => ({
          id: p.ProductoID ?? p.id,
          nombre: p.Nombre ?? p.nombre,
          descripcion: p.Descripcion ?? p.descripcion,
          precio: p.Precio ?? p.precio,
          stock: p.Stock ?? p.stock,
          imagen: p.Imagen ?? p.imagen,
        }))
      );
    } catch (error) {
      console.error("❌ Error al obtener productos:", error);
    } finally {
      setLoading(false);
    }
  }, [categoria_id]);

  useEffect(() => {
    obtenerProductos();
  }, [obtenerProductos]);

  if (loading) {
    return <p className="text-center mt-5">Cargando...</p>;
  }

  // 📄 LÓGICA DE PAGINACIÓN
  const totalPaginas = Math.ceil(productos.length / productosPorPagina);
  const inicio = (paginaActual - 1) * productosPorPagina;
  const productosPaginados = productos.slice(
    inicio,
    inicio + productosPorPagina
  );
  const handleChange = (e) => {
  setNuevoProducto({
    ...nuevoProducto,
    [e.target.name]: e.target.value,
  });
};

const handleFileChange = (e) => {
  setNuevoProducto({
    ...nuevoProducto,
    imagen: e.target.files[0],
  });
};

const guardarProducto = async (e) => {
  e.preventDefault();

  try {
    const formData = new FormData();
    formData.append("Nombre", nuevoProducto.nombre);
    formData.append("Descripcion", nuevoProducto.descripcion);
    formData.append("Precio", nuevoProducto.precio);
    formData.append("Stock", nuevoProducto.stock);
    formData.append("categoria_id", categoria_id); // 🔥 AUTOMÁTICO

    if (nuevoProducto.imagen) {
      formData.append("Imagen", nuevoProducto.imagen);
    }

    await axios.post("http://localhost:5000/api/productos", formData, {
      headers: { "Content-Type": "multipart/form-data" },
    });

    setShowModal(false);
    setNuevoProducto({
      nombre: "",
      descripcion: "",
      precio: "",
      stock: "",
      imagen: null,
    });

    obtenerProductos(); // 🔄 refresca la lista
  } catch (error) {
    console.error("❌ Error al crear producto:", error);
  }
};


  return (
    <div className="container mt-4">
      <button className="btn btn-secondary mb-3" onClick={() => navigate(-1)}>
        ⬅ Volver
      </button>
      <div className="d-flex justify-content-between align-items-center mb-3">
  <h4 className="mb-0">Productos de la categoría</h4>

  <button
    className="btn btn-success btn-sm"
    onClick={() => setShowModal(true)}
  >
    ➕ Agregar producto
  </button>
</div>


      <h4 className="mb-4 text-center">Productos de la categoría</h4>

      <div className="row g-3">
        {productosPaginados.length === 0 && (
          <p className="text-center">No hay productos en esta categoría</p>
        )}

        {productosPaginados.map((p) => (
          <div key={p.id} className="col-lg-3 col-md-4 col-sm-6">
            <div className="card shadow-sm h-100 border-0">
              {p.imagen ? (
                <img
                  src={`http://localhost:5000/uploads/${p.imagen}`}
                  alt={p.nombre}
                  className="card-img-top"
                  style={{
                    height: "120px",
                    objectFit: "cover",
                  }}
                />
              ) : (
                <div
                  className="bg-light d-flex align-items-center justify-content-center text-muted"
                  style={{ height: "120px" }}
                >
                  Sin imagen
                </div>
              )}
              {showModal && (
  <div
    className="modal fade show"
    style={{ display: "block", background: "rgba(0,0,0,.6)" }}
  >
    <div className="modal-dialog modal-dialog-centered modal-lg">
      <div className="modal-content p-4">
        <h5 className="mb-3">Agregar producto</h5>

        <form onSubmit={guardarProducto} encType="multipart/form-data">
          <div className="row g-2">
            <div className="col-md-6">
              <input
                name="nombre"
                className="form-control"
                placeholder="Nombre"
                onChange={handleChange}
                required
              />
            </div>

            <div className="col-md-6">
              <input
                name="precio"
                type="number"
                step="0.01"
                className="form-control"
                placeholder="Precio"
                onChange={handleChange}
                required
              />
            </div>

            <div className="col-md-12">
              <textarea
                name="descripcion"
                className="form-control"
                placeholder="Descripción"
                onChange={handleChange}
              />
            </div>

            <div className="col-md-6">
              <input
                name="stock"
                type="number"
                className="form-control"
                placeholder="Stock"
                onChange={handleChange}
                required
              />
            </div>

            <div className="col-md-6">
              <input
                type="file"
                accept="image/*"
                className="form-control"
                onChange={handleFileChange}
              />
            </div>
          </div>

          <div className="text-end mt-4">
            <button
              type="button"
              className="btn btn-secondary me-2"
              onClick={() => setShowModal(false)}
            >
              Cancelar
            </button>

            <button className="btn btn-primary">
              Guardar producto
            </button>
          </div>
        </form>
      </div>
    </div>
  </div>
)}


              <div className="card-body p-2">
                <h6 className="fw-semibold text-truncate mb-1">
                  {p.nombre}
                </h6 >
                <h6 className="fw-bold text-success mb-1">
                  Stock: {p.stock}
                </h6>
                 <small className="fw-bold text-success">
                  ${p.precio}
                </small>

                <small className="text-muted d-block text-truncate">
                  {p.descripcion}
                </small>

               
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* 📄 CONTROLES DE PAGINACIÓN */}
      {totalPaginas > 1 && (
        <nav className="mt-4">
          <ul className="pagination justify-content-center">
            <li className={`page-item ${paginaActual === 1 && "disabled"}`}>
              <button
                className="page-link"
                onClick={() => setPaginaActual(paginaActual - 1)}
              >
                Anterior
              </button>
            </li>

            {[...Array(totalPaginas)].map((_, i) => (
              <li
                key={i}
                className={`page-item ${
                  paginaActual === i + 1 ? "active" : ""
                }`}
              >
                <button
                  className="page-link"
                  onClick={() => setPaginaActual(i + 1)}
                >
                  {i + 1}
                </button>
              </li>
            ))}

            <li
              className={`page-item ${
                paginaActual === totalPaginas && "disabled"
              }`}
            >
              <button
                className="page-link"
                onClick={() => setPaginaActual(paginaActual + 1)}
              >
                Siguiente
              </button>
            </li>
          </ul>
        </nav>
      )}
    </div>
  );
}
